import{_ as n,o as t,c as o,a3 as r}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"98. Industry Ohs Working Group","description":"","frontmatter":{"title":"98. Industry Ohs Working Group","eba":"Allied Health Professionals 2021-2026","topics":["ohs","workers-comp"]},"headers":[],"relativePath":"ebas/allied-health/ohs/98-industry-ohs-working-group.md","filePath":"ebas/allied-health/ohs/98-industry-ohs-working-group.md"}'),a={name:"ebas/allied-health/ohs/98-industry-ohs-working-group.md"};function i(s,e,p,d,l,g){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="_98-industry-ohs-working-group" tabindex="-1">98. Industry Ohs Working Group <a class="header-anchor" href="#_98-industry-ohs-working-group" aria-label="Permalink to &quot;98. Industry Ohs Working Group&quot;">​</a></h1><p><strong>98.1</strong> The Employers (and the VHIA), the Employees and the Union will proactively cooperate in development and recommendation of measures to improve occupational health and safety outcomes, with the intent of improving employee health and safety, preventing injury, illness and incapacity (and hence workers compensation payments), particularly with respect to the following:</p><p><strong>(a)</strong> safe patient and manual handling processes;</p><p><strong>(b)</strong> safe rostering practices and prevention of fatigue risks;</p><p><strong>(c)</strong> occupational violence and aggression prevention programs;</p><p><strong>(d)</strong> education for Assistant Allied Health Managers, Allied Health Managers and other managers covered by this Agreement regarding management of employees; and</p><p><strong>(e)</strong> workplace bullying.</p><p><strong>98.2</strong> The proactive cooperation described at subclause 98.1 with respect to the priorities identified above, will seek to achieve the following:</p><p><strong>(a)</strong> in the case of safe patient and manual handling processes, reduction of musculoskeletal injuries by identifying requirements for safe patient and manual handling programs including recommendation of principles and practices to prevent and reduce the associated risks;</p><p><strong>(b)</strong> in the case of safe rostering practices, identification of staff and patient safety risks associated with working hours, shift work, rostering practices and fatigue, including any preventable hazards, and recommendation of principles and practices to prevent and reduce the associated risks;</p><p><strong>(c)</strong> in the case of occupational violence and aggression prevention programs, ensuring the prevention and/or appropriate management of occupational violence to reduce associated injuries and illness, including the long term mental health implications of exposure to continuing violence and aggression, including recommendation of principles and practices to prevent and reduce the associated risks, and making recommendations to address these;</p><p><strong>(d)</strong> in the case of education and training of Assistant Allied Health Managers, Allied Health Managers and other managers covered by this Agreement, appropriate understanding of management obligations in relation to occupational health and safety, workers compensation and return to work by identifying gaps and making recommendations to address these; and</p><p><strong>(e)</strong> in the case of workplace bullying, identification of bullying prevention principles and practices, including education on early identification and intervention, appropriate workplace behaviour/Code of Conduct and appropriate investigation and feedback processes, and making recommendations to implement these.</p><p><strong>98.3</strong> As these matters are relevant to all employees and Employers covered by this Agreement, an Industry OHS Working Group will be established consisting of no more than three (3) representatives from each of the following:</p><p><strong>(a)</strong> the Union;</p><p><strong>(b)</strong> VHIA;</p><p><strong>(c)</strong> Department; and</p><p><strong>(d)</strong> other attendees as agreed by members of the working party.</p><p><strong>98.4</strong> In the case of the Union and VHIA, a representative may include a member.</p><p><strong>98.5</strong> The Industry OHS Working Group will commence meeting within three (3) months of the commencement of the Agreement, and will meet bi-monthly or otherwise by agreement between its members.</p><p><strong>98.6</strong> The Industry OHS Working Group will determine any actions it will undertake, in addition to the above priorities.</p><p><strong>98.7</strong> The Industry OHS Working Group will operate with the oversight of the BPECC and will produce annual reports to be provided to all parties on the progress, actions and recommendations resulting from the Group’s work, with the first report to be delivered to the BPECC no more than 12 months after the first meeting.</p>',22)])])}const m=n(a,[["render",i]]);export{h as __pageData,m as default};
